function pinPosition(shape?: StateShape) {
  if (!shape) return { left: "68%", top: "34%" };
  return {
    left: `${(shape.center[0] / 360) * 100}%`,
    top: `${(shape.center[1] / 430) * 100}%`,
  };
}

export function IndiaZoomMap({ selectedState, className = "" }: IndiaZoomMapProps) {
  const selectedName = ALIASES[selectedState] ?? selectedState;
  const selectedShape = STATE_SHAPES.find((shape) => shape.name === selectedName);
  const transform = useMemo(() => {
    if (!selectedShape) return "translate(0 0) scale(1)";
    const [cx, cy] = selectedShape.center;
    const scale = selectedShape.zoom;
    return `translate(180 210) scale(${scale}) translate(${-cx} ${-cy})`;
  }, [selectedShape]);

  const pin = pinPosition(selectedShape);

  return (
    <div className={`relative mx-auto aspect-[360/430] w-full max-w-[360px] ${className}`}>
      <svg viewBox="0 0 360 430" role="img" aria-label="Map of India" className="h-full w-full overflow-visible">
        <g className="transition-transform duration-1000 ease-[cubic-bezier(.2,.85,.2,1)]" transform={transform}>
          {STATE_SHAPES.map((shape) => {
            const active = shape.name === selectedName;
            return (
              <path
                key={shape.name}
                d={shape.path}
                className={active ? "india-state india-state-active" : "india-state"}
                vectorEffect="non-scaling-stroke"
              />
            );
          })}
        </g>
      </svg>

      <div
        className={`pointer-events-none absolute -translate-x-1/2 -translate-y-full transition-all duration-1000 ease-[cubic-bezier(.2,.85,.2,1)] ${selectedShape ? "scale-100 opacity-100" : "scale-90 opacity-0"}`}
        style={pin}
        aria-hidden
      >
        <svg width="24" height="30" viewBox="0 0 24 30" fill="none" className="drop-shadow-[0_0_10px_rgba(255,255,255,.55)]">
          <path d="M12 0C5.4 0 0 5.4 0 12c0 9 12 18 12 18s12-9 12-18C24 5.4 18.6 0 12 0zm0 16a4 4 0 110-8 4 4 0 010 8z" fill="white" />
        </svg>
      </div>
    </div>
  );
}
